# ---- Session CRUD ----


async def upsert_session(
    db: aiosqlite.Connection,
    *,
    session_id: str,
    pid: int = 0,
    cwd: str = "",
    entrypoint: str = "cli",
    started_at: int = 0,
    last_event: str | None = None,
    last_tool: str | None = None,
    last_event_at: float | None = None,
    branch: str = "",
    source_system: str = "",
) -> None:
    """Insert or update a session row. On conflict, update event fields."""
    now = time.time()
    await db.execute(
        """
        INSERT INTO claude_sessions
            (session_id, pid, cwd, entrypoint, started_at,
             last_event, last_tool, last_event_at, discovered_at, branch,
             source_system)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(session_id) DO UPDATE SET
            last_event = COALESCE(excluded.last_event, last_event),
            last_tool = COALESCE(excluded.last_tool, last_tool),
            last_event_at = COALESCE(excluded.last_event_at, last_event_at),
            cwd = CASE WHEN excluded.cwd != '' THEN excluded.cwd ELSE cwd END,
            pid = CASE WHEN excluded.pid != 0 THEN excluded.pid ELSE pid END,
            entrypoint = CASE
                WHEN excluded.entrypoint != 'cli' THEN excluded.entrypoint
                ELSE entrypoint
            END,
            started_at = CASE
                WHEN started_at = 0 THEN excluded.started_at
                ELSE started_at
            END,
            source_system = CASE
                WHEN excluded.source_system != '' THEN excluded.source_system
                ELSE source_system
            END,
            pid_alive = CASE
                WHEN excluded.last_event = 'SessionEnd' THEN pid_alive
                ELSE 1
            END,
            ended_at = CASE
                WHEN excluded.last_event = 'SessionEnd' THEN ended_at
                ELSE NULL
            END
        """,
        (
            session_id,
            pid,
            cwd,
            entrypoint,
            started_at,
            last_event,
            last_tool,
            last_event_at,
            now,
            branch,
            source_system,
        ),
    )
    await db.commit()


async def end_session(
    db: aiosqlite.Connection,
    *,
    session_id: str,
    ended_at: float | None = None,
) -> None:
    """Mark a session as ended."""
    ts = time.time() if ended_at is None else ended_at
    await db.execute(
        "UPDATE claude_sessions SET ended_at = ? WHERE session_id = ?",
        (ts, session_id),
    )
    await db.commit()


async def update_session_pid_alive(
    db: aiosqlite.Connection,
    *,
    session_id: str,
    pid_alive: bool,
) -> None:
    """Update the pid_alive flag for a session."""
    await db.execute(
        "UPDATE claude_sessions SET pid_alive = ? WHERE session_id = ?",
        (1 if pid_alive else 0, session_id),
    )
    await db.commit()


async def get_all_sessions(
    db: aiosqlite.Connection,
    *,
    active: bool | None = None,
) -> list[dict]:
    """Return all sessions, optionally filtered by active status."""
    query = "SELECT * FROM claude_sessions"
    params: list[object] = []

    if active is True:
        query += " WHERE pid_alive = 1 AND ended_at IS NULL"
    elif active is False:
        query += " WHERE pid_alive = 0 OR ended_at IS NOT NULL"

    query += " ORDER BY started_at DESC"
    cursor = await db.execute(query, params)
    rows = await cursor.fetchall()
    return [dict(row) for row in rows]


async def get_session(
    db: aiosqlite.Connection,
    *,
    session_id: str,
) -> dict | None:
    """Return a single session by ID."""
    cursor = await db.execute(
        "SELECT * FROM claude_sessions WHERE session_id = ?",
        (session_id,),
    )
    row = await cursor.fetchone()
    return dict(row) if row else None


async def get_sessions_needing_pid_check(
    db: aiosqlite.Connection,
) -> list[dict]:
    """Return sessions that are alive and not ended."""
    cursor = await db.execute(
        "SELECT * FROM claude_sessions WHERE pid_alive = 1 AND ended_at IS NULL"
    )
    rows = await cursor.fetchall()
    return [dict(row) for row in rows]


async def clear_session(
    db: aiosqlite.Connection,
    *,
    session_id: str,
    cleared_at: float | None = None,
) -> None:
    """Reset a session's current state as if freshly connected.

    Clears last_event/last_tool/last_event_at on the session and ends
    all active agents. Historical events remain intact.
    """
    ts = time.time() if cleared_at is None else cleared_at
    await db.execute(
        """
        UPDATE claude_sessions
        SET last_event = NULL, last_tool = NULL, last_event_at = NULL
        WHERE session_id = ?
        """,
        (session_id,),
    )
    await db.execute(
        """
        UPDATE claude_agents
        SET ended_at = ?
        WHERE session_id = ? AND ended_at IS NULL
        """,
        (ts, session_id),
    )
    await db.commit()


