async def upsert_agent(
    db: aiosqlite.Connection,
    *,
    agent_id: str,
    session_id: str,
    agent_type: str = "",
    last_event: str | None = None,
    last_tool: str | None = None,
    last_event_at: float | None = None,
) -> None:
    """Insert or update an agent row."""
    now = time.time()
    await db.execute(
        """
        INSERT INTO claude_agents
            (agent_id, session_id, agent_type, last_event, last_tool,
             last_event_at, started_at)
        VALUES (?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(agent_id) DO UPDATE SET
            last_event = COALESCE(excluded.last_event, last_event),
            last_tool = COALESCE(excluded.last_tool, last_tool),
            last_event_at = COALESCE(excluded.last_event_at, last_event_at),
            agent_type = CASE
                WHEN excluded.agent_type != '' THEN excluded.agent_type
                ELSE agent_type
            END
        """,
        (agent_id, session_id, agent_type, last_event, last_tool, last_event_at, now),
    )
    await db.commit()


