async def get_prior_costs_by_session_ids(
    db: aiosqlite.Connection,
    *,
    session_ids: list[str],
    before_ts: float,
) -> dict[str, float]:
    """Return max cumulative cost_usd per session from statusline rows
    recorded strictly before `before_ts`.

    Sessions with no qualifying rows are absent from the returned dict;
    callers should default to 0.0.
    """
    if not session_ids:
        return {}
    placeholders = ",".join("?" for _ in session_ids)
    cursor = await db.execute(
        f"""
        SELECT session_id, MAX(cost_usd) AS prior_cost
        FROM claude_statusline
        WHERE session_id IN ({placeholders})
          AND received_at < ?
          AND cost_usd IS NOT NULL
        GROUP BY session_id
        """,
        [*session_ids, before_ts],
    )
    rows = await cursor.fetchall()
    return {row["session_id"]: row["prior_cost"] for row in rows}


async def get_prior_cost(
    db: aiosqlite.Connection,
    *,
    session_id: str,
    before_ts: float,
) -> float:
    """Return max cumulative cost_usd for a single session before `before_ts`.
    Returns 0.0 if no qualifying rows exist.
    """
    cursor = await db.execute(
        """
        SELECT MAX(cost_usd) AS prior_cost
        FROM claude_statusline
        WHERE session_id = ?
          AND received_at < ?
          AND cost_usd IS NOT NULL
        """,
        (session_id, before_ts),
    )
    row = await cursor.fetchone()
    if row is None or row["prior_cost"] is None:
        return 0.0
    return float(row["prior_cost"])


async def update_session_statusline(
    db: aiosqlite.Connection,
    *,
    session_id: str,
    cost_usd: float | None = None,
    context_used_pct: float | None = None,
    model_name: str | None = None,
    total_input_tokens: int | None = None,
    total_output_tokens: int | None = None,
    lines_added: int | None = None,
    lines_removed: int | None = None,
) -> None:
    """Update a session's cost/context/model/token/lines fields."""
    await db.execute(
        """
        UPDATE claude_sessions SET
            cost_usd = COALESCE(?, cost_usd),
            context_used_pct = COALESCE(?, context_used_pct),
            model_name = COALESCE(?, model_name),
            total_input_tokens = COALESCE(?, total_input_tokens),
            total_output_tokens = COALESCE(?, total_output_tokens),
            lines_added = COALESCE(?, lines_added),
            lines_removed = COALESCE(?, lines_removed)
        WHERE session_id = ?
        """,
        (
            cost_usd,
            context_used_pct,
            model_name,
            total_input_tokens,
            total_output_tokens,
            lines_added,
            lines_removed,
            session_id,
        ),
    )
    await db.commit()


# ---- v1 → v2 replay migration (slice A1) ------------------------------------
# One-shot replay of v1 raw_payload columns into the v2 log tables. Idempotent:
# if either v2 table already has rows, this function is a no-op. The first
# successful run fills both tables; subsequent runs see non-empty tables and
# return early.
#
# Pid-less rows (raw_payload without a "pid" field, mostly day-one records
# from before the relay's pid injection) are dropped — they would orphan in
# v2's process derivation. See docs/old/data-migration.md for the rationale.


async def _table_is_empty(db: aiosqlite.Connection, table: str) -> bool:
    cursor = await db.execute(f"SELECT 1 FROM {table} LIMIT 1")
    row = await cursor.fetchone()
    return row is None


async def _entrypoint_for_session(
    db: aiosqlite.Connection, *, session_id: str
) -> str | None:
    cursor = await db.execute(
        "SELECT entrypoint FROM claude_sessions WHERE session_id = ?",
        (session_id,),
    )
    row = await cursor.fetchone()
    if row is None:
        return None
    val = row["entrypoint"]
    return val if val else None


def _ms_to_seconds(value: object) -> float | None:
    """Return ms / 1000 as float, or None if value is missing/non-numeric."""
    if isinstance(value, (int, float)):
        return float(value) / 1000.0
    return None


# ---- v2 log inserters --------------------------------------------------------
# These are the canonical "payload → v2 row" inserters. Used by the v1 replay
# migration today and by the live /hooks/claude and /statusline/claude endpoints
# in slice A2. Centralizing the field extraction keeps the migration and the
# live ingestion path producing identical rows for identical payloads.
#
# Both functions return True when a row was inserted, False when it was
# skipped because the payload had no `pid`. Callers decide whether to count
# or log skips.


async def insert_log_hook(
    db: aiosqlite.Connection,
    *,
    payload: dict,
    received_at: float,
    received_by: str,
    entrypoint: str | None = None,
    raw_payload: str | None = None,
) -> int | None:
    """Insert a hook payload into claude_log_hooks.

    All v2-column values are extracted from `payload`. The two pieces that
    are NOT in the payload and therefore must be supplied by the caller:
    - `received_at` / `received_by` — the wire-receipt audit pair
    - `entrypoint` — server-side psutil lookup at live ingestion, or
      sessions-table lookup during the v1→v2 replay

    `raw_payload` defaults to `json.dumps(payload)`. Callers that already
    have the original byte-for-byte text (the v1 replay path) should pass
    it explicitly to preserve provenance.

    Returns the new row's id, or None (without inserting) if `payload`
    lacks a `pid` field — such rows would orphan in v2's process derivation.
    See docs/old/data-migration.md.
    """
    if not isinstance(payload, dict) or "pid" not in payload:
        return None

    resolved_raw = raw_payload if raw_payload is not None else json.dumps(payload)

    cursor = await db.execute(
        """
        INSERT INTO claude_log_hooks (
            pid, session_id, source_system, cwd, agent_id,
            event_name, tool_name, agent_type, permission_mode,
            entrypoint, claude_version,
            received_at, received_by, raw_payload
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            int(payload["pid"]),
            payload.get("session_id", ""),
            payload.get("source_system", ""),
            payload.get("cwd", ""),
            payload.get("agent_id") or None,  # wire form is "" for absent
            payload.get("hook_event_name", ""),
            payload.get("tool_name") or None,
            payload.get("agent_type") or None,
            payload.get("permission_mode") or None,
            entrypoint,
            payload.get("claude_version") or None,
            received_at,
            received_by,
            resolved_raw,
        ),
    )
    return cursor.lastrowid


async def insert_log_statusline(
    db: aiosqlite.Connection,
    *,
    payload: dict,
    received_at: float,
    received_by: str,
    raw_payload: str | None = None,
) -> int | None:
    """Insert a statusline payload into claude_log_statuslines.

    All v2-column values are extracted from `payload`. The wire-receipt
    audit pair (`received_at`, `received_by`) is supplied by the caller.
    `raw_payload` defaults to `json.dumps(payload)`; pass explicitly to
    preserve original byte-for-byte text.

    Returns the new row's id, or None (without inserting) if `payload`
    lacks a `pid` field.
    """
    if not isinstance(payload, dict) or "pid" not in payload:
        return None

    workspace = payload.get("workspace") or {}
    model = payload.get("model") or {}
    cost = payload.get("cost") or {}
    ctx = payload.get("context_window") or {}
    current_usage = ctx.get("current_usage") or {}
    resolved_raw = raw_payload if raw_payload is not None else json.dumps(payload)

    cursor = await db.execute(
        """
        INSERT INTO claude_log_statuslines (
            pid, session_id, source_system, cwd,
            project_dir, model_id, model_name, claude_version,
            cost_usd, total_input_tokens, total_output_tokens,
            context_used_pct, context_window_size,
            cache_read_tokens, cache_creation_tokens,
            duration_seconds, api_duration_seconds,
            lines_added, lines_removed, exceeds_200k_tokens,
            received_at, received_by, raw_payload
        ) VALUES (
            ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?,
            ?, ?, ?
        )
        """,
        (
            int(payload["pid"]),
            payload.get("session_id", ""),
            payload.get("source_system", ""),
            # Statusline payloads sometimes omit top-level cwd and only
            # carry workspace.project_dir (Claude Code SDK pattern). Mirror
            # v1's fallback chain so identity matches between hooks and
            # statuslines for the same process.
            payload.get("cwd") or workspace.get("project_dir") or "",
            workspace.get("project_dir") or None,
            model.get("id") or None,
            model.get("display_name") or None,
            payload.get("version") or None,
            cost.get("total_cost_usd"),
            ctx.get("total_input_tokens"),
            ctx.get("total_output_tokens"),
            ctx.get("used_percentage"),
            ctx.get("context_window_size"),
            current_usage.get("cache_read_input_tokens"),
            current_usage.get("cache_creation_input_tokens"),
            _ms_to_seconds(cost.get("total_duration_ms")),
            _ms_to_seconds(cost.get("total_api_duration_ms")),
            cost.get("total_lines_added"),
            cost.get("total_lines_removed"),
            1 if payload.get("exceeds_200k_tokens") else 0,
            received_at,
            received_by,
            resolved_raw,
        ),
    )
    return cursor.lastrowid


# ---- v1 → v2 replay -----------------------------------------------------------


async def _replay_hooks_from_v1(db: aiosqlite.Connection) -> int:
    """Replay claude_events rows into claude_log_hooks. Returns inserted count.

    raw_payload from v1 is the source of truth for every v2 column except
    entrypoint (which agentpulse computed at v1 ingestion via psutil and
    stored on claude_sessions, not in the payload). We hand insert_log_hook
    the original raw_payload bytes so provenance is preserved.
    """
    cursor = await db.execute(
        "SELECT session_id, received_at, raw_payload FROM claude_events "
        "ORDER BY received_at, id"
    )
    src_rows = await cursor.fetchall()

    inserted = 0
    skipped_no_pid = 0
    entrypoint_cache: dict[str, str | None] = {}

    for row in src_rows:
        try:
            payload = json.loads(row["raw_payload"]) if row["raw_payload"] else {}
        except json.JSONDecodeError:
            payload = {}

        sid = row["session_id"]
        if sid not in entrypoint_cache:
            entrypoint_cache[sid] = await _entrypoint_for_session(db, session_id=sid)

        log_id = await insert_log_hook(
            db,
            payload=payload,
            received_at=row["received_at"],
            received_by="hook-endpoint-v1-replay",
            entrypoint=entrypoint_cache.get(sid),
            raw_payload=row["raw_payload"],
        )
        if log_id is not None:
            inserted += 1
        else:
            skipped_no_pid += 1

    if skipped_no_pid:
        logger.info(
            "replay_v1_to_v2_logs: dropped %d pid-less hook rows", skipped_no_pid
        )
    return inserted


async def _hook_pid_index_for_session(
    db: aiosqlite.Connection, *, session_id: str
) -> list[tuple[float, int, str]]:
    """Per-session list of (received_at, pid, cwd) tuples from claude_events.

    Used by the v1 statusline replay to realign mismatched-pid statuslines
    onto the closest hook's pid. Returned tuples are sorted by received_at.
    """
    cursor = await db.execute(
        "SELECT received_at, raw_payload FROM claude_events "
        "WHERE session_id = ? ORDER BY received_at",
        (session_id,),
    )
    rows = await cursor.fetchall()
    out: list[tuple[float, int, str]] = []
    for r in rows:
        try:
            p = json.loads(r["raw_payload"]) if r["raw_payload"] else {}
        except json.JSONDecodeError:
            continue
        if not isinstance(p, dict):
            continue
        pid_val = p.get("pid")
        if not isinstance(pid_val, int):
            continue
        out.append((float(r["received_at"]), pid_val, p.get("cwd", "") or ""))
    return out


def _normalize_statusline_pid(
    hook_index: list[tuple[float, int, str]],
    *,
    statusline_cwd: str,
    statusline_received_at: float,
) -> int | None:
    """Find the pid of the hook at the same cwd with the closest received_at.

    Returns None when no hook in the session shares the statusline's cwd —
    in that case the caller leaves the original pid in place. Used to
    repair legacy SDK statuslines whose relay injected a pid unrelated to
    the SDK's actual Claude Code process pid (the hook relay does it
    correctly via getppid).
    """
    candidates = [(t, pid) for t, pid, cwd in hook_index if cwd == statusline_cwd]
    if not candidates:
        return None
    return min(candidates, key=lambda x: abs(x[0] - statusline_received_at))[1]


async def _replay_statuslines_from_v1(db: aiosqlite.Connection) -> int:
    """Replay claude_statusline rows into claude_log_statuslines.

    For legacy data where the statusline relay injected a pid that doesn't
    match the hook relay's pid for the same logical Claude Code process
    (the SDK in-process pattern), this re-aligns each statusline's pid to
    the closest matching hook's pid before insert. The original payload
    bytes are preserved verbatim in raw_payload; only the extracted pid
    column is normalized. After the SDK relay fix lands, new statuslines
    arrive with the correct pid and don't need normalization.
    """
    cursor = await db.execute(
        "SELECT received_at, raw_payload FROM claude_statusline "
        "ORDER BY received_at, id"
    )
    src_rows = await cursor.fetchall()

    inserted = 0
    skipped_no_pid = 0
    realigned = 0
    hook_index_cache: dict[str, list[tuple[float, int, str]]] = {}

    for row in src_rows:
        try:
            payload = json.loads(row["raw_payload"]) if row["raw_payload"] else {}
        except json.JSONDecodeError:
            payload = {}

        if isinstance(payload, dict):
            sid = payload.get("session_id", "")
            workspace = payload.get("workspace") or {}
            sl_cwd = payload.get("cwd") or workspace.get("project_dir") or ""
            if sid:
                if sid not in hook_index_cache:
                    hook_index_cache[sid] = await _hook_pid_index_for_session(
                        db, session_id=sid
                    )
                normalized_pid = _normalize_statusline_pid(
                    hook_index_cache[sid],
                    statusline_cwd=sl_cwd,
                    statusline_received_at=float(row["received_at"]),
                )
                if normalized_pid is not None and normalized_pid != payload.get("pid"):
                    payload = {**payload, "pid": normalized_pid}
                    realigned += 1

        log_id = await insert_log_statusline(
            db,
            payload=payload,
            received_at=row["received_at"],
            received_by="statusline-endpoint-v1-replay",
            raw_payload=row["raw_payload"],
        )
        if log_id is not None:
            inserted += 1
        else:
            skipped_no_pid += 1

    if skipped_no_pid:
        logger.info(
            "replay_v1_to_v2_logs: dropped %d pid-less statusline rows",
            skipped_no_pid,
        )
    if realigned:
        logger.info(
            "replay_v1_to_v2_logs: realigned %d statusline pids to nearest hook",
            realigned,
        )
    return inserted


async def _replay_api_limits_from_v1(db: aiosqlite.Connection) -> int:
    """Replay claude_limits rows into claude_log_api_limits.

    v1 stored each fetch with `fetched_at` and the full `raw_response`.
    v2's inserter extracts and ISO-normalizes the bucket fields. Other
    columns (e.g. v1's stale_after) aren't carried over — they were
    operational metadata, not row content.
    """
    cursor = await db.execute(
        "SELECT fetched_at, raw_response FROM claude_limits " "ORDER BY fetched_at, id"
    )
    src_rows = await cursor.fetchall()

    inserted = 0
    for row in src_rows:
        if not row["raw_response"]:
            continue
        await insert_log_api_limits(
            db,
            received_at=row["fetched_at"],
            received_by="limits-fetcher-v1-replay",
            raw_response=row["raw_response"],
        )
        inserted += 1
    return inserted


async def replay_v1_to_v2_logs(db: aiosqlite.Connection) -> dict[str, int]:
    """Per-target-table replay of v1 source data into v2 log tables.

    Each target table self-gates: an empty v2 target triggers replay from
    the corresponding v1 source; a populated v2 target is left alone. This
    lets new v2 tables added in later slices catch up on existing
    deployments — earlier replays don't lock new ones out.

    Returns a dict with insert counts per target table (0 each when
    skipped). Skips v1 hook / statusline rows whose raw_payload lacks a
    `pid` field (see docs/old/data-migration.md).
    """
    counts = {"hooks": 0, "statuslines": 0, "api_limits": 0}

    if await _table_is_empty(db, "claude_log_hooks"):
        counts["hooks"] = await _replay_hooks_from_v1(db)
    else:
        logger.debug("replay: claude_log_hooks already populated, skipping")

    if await _table_is_empty(db, "claude_log_statuslines"):
        counts["statuslines"] = await _replay_statuslines_from_v1(db)
    else:
        logger.debug("replay: claude_log_statuslines already populated, skipping")

    if await _table_is_empty(db, "claude_log_api_limits"):
        counts["api_limits"] = await _replay_api_limits_from_v1(db)
    else:
        logger.debug("replay: claude_log_api_limits already populated, skipping")

    await db.commit()

    if any(counts.values()):
        logger.info(
            "replay_v1_to_v2_logs: replayed %d hooks, %d statuslines, %d api_limits",
            counts["hooks"],
            counts["statuslines"],
            counts["api_limits"],
        )

    return counts


# ---- v2 pid-deaths inserter (slice B) ---------------------------------------


async def insert_log_pid_death(
    db: aiosqlite.Connection,
    *,
    pid: int,
    source_system: str,
    cwd: str,
    observed_at: float,
    observed_by: str,
) -> int:
    """Insert one death observation into claude_log_pid_deaths.

    The watcher writes here when its OS check confirms a Claude PID is gone.
    Multiple rows may share the same (pid, source_system, cwd) over time
    (PID reuse) — the natural identity composite is process-instance-shaped,
    not row-unique; uniqueness is the autoincrement id.

    Always inserts (no skip path). Returns the new row's id.
    """
    cursor = await db.execute(
        """
        INSERT INTO claude_log_pid_deaths (
            pid, source_system, cwd, observed_at, observed_by
        ) VALUES (?, ?, ?, ?, ?)
        """,
        (pid, source_system, cwd, observed_at, observed_by),
    )
    assert cursor.lastrowid is not None
    return cursor.lastrowid


# ---- v2 api-limits inserter (slice C) ---------------------------------------


def _iso_to_epoch_seconds(value: object) -> float | None:
    """Parse an ISO-8601 datetime string to Unix epoch seconds.

    The Anthropic OAuth API returns resets_at as ISO strings (e.g.
    `"2026-04-13T07:00:00+00:00"`); v2 stores epoch seconds throughout.
    Returns None when the input is None, empty, or unparseable.
    """
    if not isinstance(value, str) or not value:
        return None
    try:
        from datetime import datetime

        return datetime.fromisoformat(value).timestamp()
    except (ValueError, TypeError):
        return None


def _extract_api_limits_fields(raw: dict) -> dict:
    """Extract normalized fields from the OAuth API response."""
    fh = raw.get("five_hour") or {}
    sd = raw.get("seven_day") or {}
    return {
        "five_hour_utilization": fh.get("utilization"),
        "five_hour_resets_at": _iso_to_epoch_seconds(fh.get("resets_at")),
        "seven_day_utilization": sd.get("utilization"),
        "seven_day_resets_at": _iso_to_epoch_seconds(sd.get("resets_at")),
    }


async def insert_log_api_limits(
    db: aiosqlite.Connection,
    *,
    received_at: float,
    received_by: str,
    raw_response: str,
) -> tuple[int, dict]:
    """Insert one limits-fetch observation into claude_log_api_limits.

    The full API JSON is stored verbatim in raw_response. Five-hour and
    seven-day utilization + resets_at are extracted and ISO-normalized to
    epoch seconds. Other buckets (seven_day_opus, seven_day_sonnet,
    extra_usage) live in raw_response only.

    Returns (log_id, extracted_fields). The extracted dict carries the
    same four fields the broadcast frame needs, so callers don't have
    to re-parse.
    """
    try:
        raw = json.loads(raw_response) if raw_response else {}
    except json.JSONDecodeError:
        raw = {}
    fields = _extract_api_limits_fields(raw if isinstance(raw, dict) else {})

    cursor = await db.execute(
        """
        INSERT INTO claude_log_api_limits (
            received_at, received_by,
            five_hour_utilization, five_hour_resets_at,
            seven_day_utilization, seven_day_resets_at,
            raw_response
        ) VALUES (?, ?, ?, ?, ?, ?, ?)
        """,
        (
            received_at,
            received_by,
            fields["five_hour_utilization"],
            fields["five_hour_resets_at"],
            fields["seven_day_utilization"],
            fields["seven_day_resets_at"],
            raw_response,
        ),
    )
    assert cursor.lastrowid is not None
    return cursor.lastrowid, fields
